<template><div><h2 id="三大概型" tabindex="-1"><a class="header-anchor" href="#三大概型" aria-hidden="true">#</a> 三大概型</h2>
<h3 id="古典概型" tabindex="-1"><a class="header-anchor" href="#古典概型" aria-hidden="true">#</a> 古典概型</h3>
<p class='katex-block'><span class="katex-display"><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML" display="block"><semantics><mrow><mi>P</mi><mo stretchy="false">(</mo><mi>A</mi><mo stretchy="false">)</mo><mo>=</mo><mfrac><mrow><mtext>事件</mtext><mi>A</mi><mtext>所包含的样本点的个数</mtext></mrow><mrow><mtext>样本空间</mtext><mi mathvariant="normal">Ω</mi><mtext>中所包含的样本点个数</mtext></mrow></mfrac></mrow><annotation encoding="application/x-tex">
P(A)=\frac{\text{事件}A\text{所包含的样本点的个数}}{\text{样本空间}\Omega \text{中所包含的样本点个数}}
</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:1em;vertical-align:-0.25em;"></span><span class="mord mathnormal" style="margin-right:0.13889em;">P</span><span class="mopen">(</span><span class="mord mathnormal">A</span><span class="mclose">)</span><span class="mspace" style="margin-right:0.2778em;"></span><span class="mrel">=</span><span class="mspace" style="margin-right:0.2778em;"></span></span><span class="base"><span class="strut" style="height:2.0463em;vertical-align:-0.686em;"></span><span class="mord"><span class="mopen nulldelimiter"></span><span class="mfrac"><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:1.3603em;"><span style="top:-2.314em;"><span class="pstrut" style="height:3em;"></span><span class="mord"><span class="mord text"><span class="mord cjk_fallback">样本空间</span></span><span class="mord">Ω</span><span class="mord text"><span class="mord cjk_fallback">中所包含的样本点个数</span></span></span></span><span style="top:-3.23em;"><span class="pstrut" style="height:3em;"></span><span class="frac-line" style="border-bottom-width:0.04em;"></span></span><span style="top:-3.677em;"><span class="pstrut" style="height:3em;"></span><span class="mord"><span class="mord text"><span class="mord cjk_fallback">事件</span></span><span class="mord mathnormal">A</span><span class="mord text"><span class="mord cjk_fallback">所包含的样本点的个数</span></span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.686em;"><span></span></span></span></span></span><span class="mclose nulldelimiter"></span></span></span></span></span></span></p>
<h3 id="几何概型" tabindex="-1"><a class="header-anchor" href="#几何概型" aria-hidden="true">#</a> 几何概型</h3>
<p class='katex-block'><span class="katex-display"><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML" display="block"><semantics><mrow><mi>P</mi><mo stretchy="false">(</mo><mi>A</mi><mo stretchy="false">)</mo><mo>=</mo><mfrac><mtext>事件A的几何度量</mtext><mrow><mtext>样本空间</mtext><mi mathvariant="normal">Ω</mi><mtext>的几何度量</mtext></mrow></mfrac></mrow><annotation encoding="application/x-tex">
